INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Client Intake Automation$q$, $q$Customizable digital intake forms capture prospect information and feed it directly into the CRM pipeline without manual re-entry.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Visual CRM Pipeline$q$, $q$A drag-and-drop pipeline view tracks leads and clients through custom stages from first contact to signed matter.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Workflow and Marketing Automation$q$, $q$No-code automation builder triggers emails, SMS, tasks, and pipeline changes based on prospect behavior such as form submissions or missed calls.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$E-Signature Engagement Letters$q$, $q$Built-in e-signature lets firms send and execute engagement letters directly from the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Round-Robin Scheduling$q$, $q$Automatically distributes consultation bookings across intake staff or attorneys.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Conflict Checking$q$, $q$Advanced conflict-of-interest checking against existing contact and matter records.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Custom Reporting and ROI Tracking$q$, $q$Dashboards tie marketing campaigns and lead sources to signed-client revenue.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$QualifyAI (add-on)$q$, $q$AI-powered lead scoring and routing to help staff prioritize the most qualified inbound leads.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Purpose-built for legal intake and ethics requirements rather than a generic CRM$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Strong no-code marketing and workflow automation for nurturing slow-to-convert leads$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Integrates with practice-management tools like Clio for a full front-to-back-office stack$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Detailed ROI and marketing-attribution reporting for firms that spend on lead generation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Round-robin scheduling and conflict checking are tailored to law firm operations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$No public pricing, so firms must go through a sales call to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$No free trial or free plan to test the platform before committing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Higher tiers can require annual contracts and minimum user counts$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Additional contacts, SMS volume, and AI features are billed as extras on top of the base plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Primarily an intake and marketing CRM, so most firms still need a separate practice-management tool for case work$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$What is Lawmatics used for?$q$, $q$Lawmatics is used by law firms to capture and manage leads, automate client intake forms and engagement letters, and run marketing workflows that nurture prospects into signed clients.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$How much does Lawmatics cost?$q$, $q$Lawmatics does not publish list prices. It is sold in Essential, Premium, and Enterprise tiers, with firms contacting sales for a custom quote; third-party trackers report an Essential-tier starting price around 99 dollars per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Does Lawmatics offer a free trial?$q$, $q$No, Lawmatics does not offer a free trial or free plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Who founded Lawmatics?$q$, $q$Lawmatics was founded in 2017 by Matt Spiegel and Roey Chasman, who previously worked together at the legal practice-management platform MyCase.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Does Lawmatics replace practice-management software like Clio?$q$, $q$No, Lawmatics focuses on CRM, intake, and marketing automation and is commonly used alongside (and integrated with) practice-management tools such as Clio rather than replacing them.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$What is QualifyAI in Lawmatics?$q$, $q$QualifyAI is a paid add-on that uses AI to score and route inbound leads so intake staff can prioritize the most qualified prospects.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Personal injury intake automation$q$, $q$High-volume PI firms use Lawmatics to capture leads from ads and referrals, auto-route them, and nurture non-responsive prospects with automated follow-up sequences.$q$, $q$Personal injury law firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Marketing ROI tracking for law firms$q$, $q$Firms track which marketing channels and campaigns generate signed clients using custom dashboards tied to the CRM pipeline.$q$, $q$Law firm marketing directors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Streamlined client onboarding$q$, $q$Firms automate intake forms, conflict checks, and e-signature engagement letters to reduce the time between first contact and a signed matter.$q$, $q$Family law, immigration, and estate planning practices$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Essential$q$, $q$Custom quote (reported from around $99/month)$q$, $q$monthly or annual$q$, NULL, $q$["Client intake","Lead management","Calendaring","Custom forms","E-signature","SMS","Task management","500 contacts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Premium$q$, $q$Custom quote$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Essential","Workflow and marketing automation","Round-robin scheduling","Advanced conflict checking","Email marketing","Custom reporting","Analytics and ROI tracking","Custom dashboards","Event management","10,000 contacts"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["Everything in Premium","Dedicated account manager","Full access to all features"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lawmatics is a client relationship management and intake automation platform designed exclusively for law firms. Rather than functioning as a full practice-management suite, it focuses on the front end of the client lifecycle: capturing leads, automating intake forms and engagement letters, and nurturing prospects through customizable marketing workflows until they convert into signed clients.$q$, $q$Founded in 2017 by former attorney Matt Spiegel and engineer Roey Chasman, both of whom previously worked together at the practice-management platform MyCase, Lawmatics is headquartered in San Diego, California. The company has raised roughly 17.5 million dollars across seed and Series A rounds from investors including Eniac Ventures, Ankona Capital, and The Legal Tech Fund, and reports serving thousands of law firm customers across the United States.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core of Lawmatics is a visual CRM pipeline paired with customizable intake forms and e-signature-enabled engagement letters, letting firms move a prospect from initial inquiry to signed client without manual data re-entry. A no-code workflow automation builder can trigger emails, SMS messages, tasks, or pipeline changes based on prospect behavior, such as an abandoned intake form or a missed consultation call.$q$, $q$Additional functionality includes round-robin appointment scheduling for consultations, built-in conflict-of-interest checking, marketing campaign and event management, and custom reporting dashboards that tie marketing spend to signed matters for ROI tracking. Two paid add-ons extend the platform further: QualifyAI, which uses AI to score and route inbound leads, and a Time and Billing module for time tracking, invoicing, and payments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lawmatics does not publish list prices; the platform is sold in three tiers, Essential, Premium, and Enterprise, and firms must contact sales for a quote based on contact volume, user seats, and desired features. Essential is capped around 500 contacts and covers core intake and CRM functionality, Premium (the most popular tier) raises the contact cap to about 10,000 and adds automation, email marketing, and analytics, and Enterprise adds a dedicated account manager and full feature access.$q$, $q$Third-party pricing trackers commonly cite an entry price around ninety-nine dollars per month for the Essential tier, with higher tiers priced well above that and typically requiring annual contracts. There is no free plan or free trial, and additional contacts, SMS/MMS volume, QualifyAI credits, and the Time and Billing add-on are billed separately from the base subscription.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3d29e78e-8c66-4222-a921-bf433a98f869', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$People Search$q$, $q$Finds and verifies business email addresses and mobile phone numbers for target prospects.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Chrome Extension Prospecting$q$, $q$Captures contact details directly from LinkedIn and company websites into LeadIQ and connected CRMs.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$CRM and Webform Enrichment$q$, $q$Automatically fills in missing contact and firmographic data on existing Salesforce or HubSpot records.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Job Change / Champion Tracking$q$, $q$Alerts reps when a past contact changes jobs, surfacing warm re-engagement opportunities.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$AI Outbound Message Writer$q$, $q$Generates personalized first-touch outreach copy based on prospect and company data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Company Search$q$, $q$Builds targeted account lists using firmographic filters.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Lando AI Account Prospecting (Enterprise)$q$, $q$An AI agent that automates account-level prospecting workflows for larger teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Team Analytics and Governance (Enterprise)$q$, $q$Admin controls, custom field mapping, Salesforce duplicate detection, and usage dashboards for revenue operations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Usable free plan with real credits, not just a locked demo$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Fast, browser-extension-based workflow that captures leads directly from LinkedIn$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Job-change tracking is a differentiated feature for re-engaging past champions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Universal credits system applies across all features rather than siloed quotas$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Native integrations with Salesforce, HubSpot, and major sales engagement tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Credits do not roll over month to month on most plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Phone number lookups consume significantly more credits than emails$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Pro plan pricing (around $200/month) can get expensive quickly for larger teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Enterprise pricing is not published and requires a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Data coverage and accuracy can vary by region compared to larger providers like ZoomInfo$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$What is LeadIQ used for?$q$, $q$LeadIQ is used by B2B sales teams to find and verify prospect contact information, enrich CRM records, and track when past contacts change jobs, streamlining outbound prospecting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Is LeadIQ free?$q$, $q$LeadIQ offers a Free plan with one user and 50 credits. Paid plans start with Pro at roughly $200/month, and Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$How do LeadIQ credits work?$q$, $q$LeadIQ uses a universal credits system where a verified email costs about 1 credit, a phone number costs up to 10 credits, and combined enrichment costs 11 credits; unused credits typically do not roll over.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Who founded LeadIQ?$q$, $q$LeadIQ was founded in 2015 by Angelo Huang and Mei Siauw and is headquartered in San Francisco with a hub in Singapore.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Does LeadIQ integrate with Salesforce and HubSpot?$q$, $q$Yes, LeadIQ natively integrates with Salesforce and HubSpot as well as sales engagement platforms like Outreach and Salesloft.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$What is LeadIQ's job-change tracking feature?$q$, $q$It automatically alerts reps when a saved contact moves to a new company, giving sales teams a timely reason to re-engage a past champion.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Outbound prospecting for SDR teams$q$, $q$SDRs use the Chrome extension to capture verified emails and phone numbers from LinkedIn and push them straight into sequences.$q$, $q$Sales development representatives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$CRM data hygiene$q$, $q$RevOps teams use CRM enrichment to keep Salesforce or HubSpot contact and account records accurate and complete.$q$, $q$Revenue operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Re-engaging past champions$q$, $q$Account executives use job-change tracking to know when a former buyer or champion moves to a new company that could become a new deal.$q$, $q$Enterprise account executives$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 user","50 credits","People search (email + mobile)","API access","Exporting","Job change tracking","Chrome extension","AI outbound message writer","Integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Pro$q$, $q$From ~$200/month$q$, $q$monthly (25% discount annually)$q$, NULL, $q$["All Free features","Scaling credit tiers (200-6,750+ credits)","Company search","CRM enrichment","Webform enrichment","30-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["5+ users","Custom credit allocation","Lando AI account prospecting","Governance controls","CSV file enrichment","Salesforce duplicate detection","Team analytics dashboards","Custom field mappings","SSO"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LeadIQ is a B2B sales prospecting platform built to help sales development reps and account executives find and verify contact information, enrich CRM records, and track when past contacts change jobs, without leaving their existing workflow. It works primarily as a browser extension and web app that integrates with LinkedIn, Salesforce, HubSpot, and major sales engagement platforms.$q$, $q$Founded in 2015 by Angelo Huang and Mei Siauw, LeadIQ is headquartered in San Francisco with an additional hub in Singapore. The company has raised roughly 40 million dollars in venture funding, including a 30 million dollar Series B in 2021, and reports annual recurring revenue in the high single-digit millions with a team of roughly 130 to 150 people.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$LeadIQ's core capability is People and Company Search, which surfaces verified business emails and mobile phone numbers directly from LinkedIn profiles or company sites via a Chrome extension, alongside CRM and webform enrichment that automatically fills in missing contact and firmographic data on existing records. Job Change (Champion) Tracking alerts reps when a former contact moves to a new company, a high-intent signal for re-engagement, and an AI outbound message writer helps draft personalized first-touch emails.$q$, $q$Enterprise customers get additional depth: an AI account-prospecting agent called Lando, governance and admin controls, bulk CSV file enrichment, Salesforce duplicate detection, team analytics dashboards, custom field mapping, and SSO, aimed at larger revenue teams that need centralized control over data quality and usage.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LeadIQ runs on a universal credits system spent across every feature: a verified email costs about one credit, a phone number costs up to ten credits, and combined email-plus-phone enrichment costs eleven credits. The Free plan includes one user and fifty credits with access to people search, exporting, the Chrome extension, job-change tracking, and the AI outbound writer.$q$, $q$The Pro plan starts at roughly 200 dollars per month with credit tiers that scale up depending on volume, and a 25 percent discount applies to annual billing along with a 30-day free trial. Enterprise pricing is custom-quoted and, per third-party purchase data, commonly lands between about 15,000 and 30,000 dollars a year for a mid-size sales team, adding AI account prospecting, governance controls, and dedicated support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('88b216db-d52e-49cb-b940-093f9a2044aa', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
