INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Drag-and-Drop Page Builder$q$, $q$No-code visual editor for building landing pages from a library of conversion-optimized templates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$AI Page Creation$q$, $q$AI-assisted page generation and copywriting that draws from a monthly pool of AI credits.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Smart Traffic$q$, $q$AI-powered visitor routing that automatically sends each visitor to the highest-converting page variant.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$A/B Split Testing$q$, $q$Manual split testing to compare page variants and measure conversion performance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Heatmaps$q$, $q$Click and scroll heatmaps that show how visitors interact with a published page.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Dynamic Text Replacement$q$, $q$Automatically personalizes headlines and copy based on the visitor's ad or search query.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Lead Enrichment$q$, $q$Appends firmographic data to form submissions so leads arrive pre-qualified.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Forms and Webhooks$q$, $q$Native lead-capture forms that connect via webhook to email marketing and CRM platforms.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$No-code builder that is fast to learn for non-technical marketers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Built-in A/B testing, heatmaps, and Smart Traffic remove the need for separate optimization tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Unlimited pages and traffic included on all core plans$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$AI page creation speeds up initial page setup$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Long operating history and mature template library$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Regular pricing (before promotional discounts) is higher than several competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Smart Traffic and heatmaps are locked behind the Optimize tier and above$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$AI credits are capped per plan and can run out on high-traffic pages$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Deeper CRM integrations (Salesforce, Marketo, HubSpot) require the top Scale tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Less suited to building full multi-step sales funnels compared to tools like ClickFunnels$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$What is Leadpages used for?$q$, $q$Leadpages is used to build, host, and optimize landing pages and simple websites for capturing leads and driving sales, without needing a developer.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$How much does Leadpages cost?$q$, $q$Leadpages has three plans: Grow at a regular price of $99/month, Optimize at $199/month, and Scale at $399/month, with introductory discounts often available and roughly 20% savings on annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Does Leadpages offer a free trial?$q$, $q$Yes, Leadpages offers a free trial, commonly cited as 7 to 14 days depending on the current promotion.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Who founded Leadpages?$q$, $q$Leadpages was founded in 2012 in Minneapolis by Clay Collins and Tracy Simmons; it was later acquired by Redbrick Technologies in 2020.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$What is Smart Traffic in Leadpages?$q$, $q$Smart Traffic is an AI feature available on the Optimize plan and above that automatically routes each visitor to the page variant most likely to convert for their device and traffic source.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Is Leadpages good for beginners?$q$, $q$Yes, its drag-and-drop editor and pre-built templates are designed for non-technical marketers and small business owners with no coding experience.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Lead generation landing pages$q$, $q$Marketers build dedicated landing pages for ad campaigns and lead magnets, using A/B testing to improve conversion rates.$q$, $q$Small business marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Webinar and course sign-up pages$q$, $q$Coaches and course creators publish registration pages with countdown timers and integrations to email and webinar tools.$q$, $q$Coaches and online course creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Agency client page delivery$q$, $q$Marketing agencies use the Scale plan's team workspaces to build and manage landing pages across multiple client accounts.$q$, $q$Marketing agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Grow$q$, $q$$99/month (promo $49/month)$q$, $q$monthly or annual (~20% savings)$q$, NULL, $q$["Unlimited traffic and pages","4 custom domains + SSL","Manual A/B testing","Dynamic text replacement","Lead enrichment (2K IP lookups/mo)","40K AI credits/month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Optimize$q$, $q$$199/month (promo $99/month)$q$, $q$monthly or annual (~20% savings)$q$, NULL, $q$["Everything in Grow","Smart Traffic AI routing","Click and scroll heatmaps","Auto-personalization","10 active integrations","24-month analytics retention","80K AI credits/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$Scale$q$, $q$$399/month$q$, $q$monthly or annual (~20% savings)$q$, NULL, $q$["Full auto-optimization loop","Team seats and workspaces","Dedicated customer success manager","25 integrations","36-month analytics retention","160K AI credits/month"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Leadpages is a no-code landing page and website builder designed to help small businesses and marketers publish conversion-focused pages quickly. It combines a drag-and-drop editor, a library of pre-built templates, and hosting with built-in analytics, A/B testing, and lead capture tools, so a single page can be published and iterated on without a developer.$q$, $q$Founded in 2012 in Minneapolis by Clay Collins and Tracy Simmons, Leadpages raised roughly 38 million dollars in venture funding, including a 5 million dollar Series A from Foundry Group and Arthur Ventures, before being acquired by Redbrick Technologies in March 2020. The company remains headquartered in Minneapolis and is currently led by CEO Michael Sacca.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$All paid Leadpages plans include unlimited pages and traffic, AI-assisted page creation using a monthly credit pool, manual A/B split testing, dynamic text replacement for personalizing page copy to ad or search traffic, and lead enrichment that appends firmographic data to form submissions. Forms support native webhooks for connecting to email marketing and CRM tools.$q$, $q$Higher tiers unlock Smart Traffic, an AI feature that automatically routes each visitor to the page variant most likely to convert for their device and traffic source, along with click and scroll heatmaps and auto-personalization. The top Scale tier adds team workspaces, a dedicated customer success manager, and deeper CRM integrations for larger marketing organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d9e98516-f585-417e-b8e1-aa7ccf705fd5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Leadpages is sold in three tiers: Grow at a regular price of 99 dollars per month, Optimize at 199 dollars per month (the most popular tier), and Scale at 399 dollars per month, with introductory discounts frequently cutting the first month or two of Grow and Optimize roughly in half. Annual billing saves about 20 percent relative to monthly pricing.$q$, $q$Each tier increases the number of custom domains, monthly AI credits, active integrations, and analytics retention window, with Smart Traffic and heatmaps unlocked starting at Optimize and dedicated support and team workspaces reserved for Scale. A separate, lower-cost HTML Pub product line (from 10 dollars per month) offers a simpler code-first page-publishing option outside the main Leadpages plans.$q$]::text[], 2);
