INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Kanban and Task Management$q$, $q$Kanban boards, task lists, and calendar views for organizing day-to-day work.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Gantt/Timeline Milestones$q$, $q$Visual timeline tracking for project milestones and deadlines.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Lean Canvas and SWOT Tools$q$, $q$Built-in strategic planning tools for early-stage product and project ideation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Project Wiki$q$, $q$A built-in wiki for documenting project knowledge alongside tasks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Timesheets and Time Tracking$q$, $q$Native time tracking and timesheet reporting tied to tasks and projects.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Retrospectives$q$, $q$Structured retrospective tools for reviewing completed sprints or projects.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$AI-Powered Task Management (Cloud)$q$, $q$AI assistance for breaking down, prioritizing, and managing tasks on paid Cloud plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$SSO via LDAP/OIDC$q$, $q$Single sign-on support for both self-hosted and Enterprise deployments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Fully free, unrestricted open-source self-hosted edition under AGPLv3$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Explicit design focus on neurodivergent and ADHD-friendly workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Built-in strategic planning tools (Lean Canvas, SWOT) beyond typical task boards$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Affordable Cloud pricing relative to mainstream project management SaaS$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Active open-source community and Discord support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Self-hosting requires technical setup and ongoing server maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$AI features and some advanced tools (strategy, program management) are Cloud-only, not in open source$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Smaller ecosystem of integrations compared to Asana, ClickUp, or Monday.com$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Enterprise pricing is not published and requires contacting sales$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Younger company (founded 2022) with a smaller support team than larger competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Is Leantime free?$q$, $q$Yes, the self-hosted Community Edition of Leantime is completely free and open source under the AGPLv3 license. A paid Cloud edition is also available starting at $8-$10 per user per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$What makes Leantime different from other project management tools?$q$, $q$Leantime is designed around goal- and motivation-based workflows rather than pure task lists, and it is explicitly built with ADHD, autism, and dyslexia in mind, aiming to reduce cognitive overload for non-project-managers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Who founded Leantime?$q$, $q$Leantime was founded in 2022 by CEO Gloria Folaron and CTO Marcel Folaron; the open-source project itself began in 2019. The company is based in Charlotte, North Carolina, and went through Techstars in 2023.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Can I self-host Leantime?$q$, $q$Yes, Leantime's Community Edition can be self-hosted for free, typically via Docker, and includes the full core feature set under an open-source license.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Does Leantime have AI features?$q$, $q$AI-powered task management is available on the paid Cloud Pro plan, which includes a monthly pool of AI credits; it is not part of the free open-source edition.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Does Leantime offer a free trial for Cloud?$q$, $q$Yes, Leantime Cloud offers a 14-day free trial on its paid plans.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Self-hosted PM for developer teams$q$, $q$Technical teams deploy the free open-source edition on their own infrastructure to avoid per-seat SaaS costs.$q$, $q$Developers and self-hosting enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$ADHD-friendly project management$q$, $q$Neurodivergent freelancers and small teams use Leantime's goal-based workflows to reduce overwhelm compared to traditional task-list tools.$q$, $q$Neurodivergent professionals and freelancers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Startup strategy and planning$q$, $q$Early-stage startups use the built-in Lean Canvas and SWOT tools alongside task management to plan and execute strategy in one place.$q$, $q$Startup founders and small product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Community Edition (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted deployment","Core task, milestone, wiki, and timesheet features","AGPLv3 open-source license","Community support","SSO via LDAP/OIDC"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Cloud Pro (Monthly)$q$, $q$$10/user/month$q$, $q$monthly$q$, NULL, $q$["All core features","Unlimited to-dos and projects","AI-powered task management","500 AI credits/user/month","14-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Cloud Pro (Annual)$q$, $q$$8/user/month$q$, $q$annual$q$, NULL, $q$["Same as Cloud Pro monthly","~17% annual discount"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["SSO","Audit logs","Data residency","Custom billing","Custom integrations","Installation and white-labeling support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Leantime is an open-source project management platform built specifically for people who are not trained project managers, with a design philosophy grounded in motivational and behavioral science rather than rigid task hierarchies. It is explicitly marketed as friendly to neurodivergent users, including people with ADHD, autism, and dyslexia, and it centers workflows around goals and strategy rather than pure task-checking.$q$, $q$The open-source codebase started in 2019, and the company was founded in 2022 by CEO Gloria Folaron, who built the tool to manage her own ADHD while working as a product manager, and CTO Marcel Folaron, a former Google and Twilio technical program manager. The company is based in Charlotte, North Carolina, and joined Techstars in 2023; the open-source project has surpassed 50,000 downloads with an active community.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Leantime's core feature set is shared across its free self-hosted edition and paid Cloud edition: Kanban boards, task lists, and calendar views for task management; Gantt/timeline views for milestones; a built-in Lean Canvas and SWOT analysis tool for strategic planning; a project wiki; timesheets and time tracking; retrospectives; and goal and idea management, alongside notification integrations for Slack, Mattermost, and Discord.$q$, $q$The paid Cloud Pro tier adds AI-powered task management backed by a monthly AI credit allowance, while Enterprise plans layer on single sign-on, audit logging, data residency controls, and custom integrations for organizations with compliance requirements. Self-hosted deployments support SSO via LDAP and OIDC as well.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cc8a6c27-5e21-4987-a514-54dffa799736', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Leantime's Community Edition is free and fully open source under the AGPLv3 license, letting anyone self-host it with no user limits and no feature paywall on the core toolset. This makes it a genuinely free alternative for developers, freelancers, and small teams comfortable managing their own server.$q$, $q$For teams that want a managed option, Leantime Cloud Pro costs 10 dollars per user per month billed monthly, or 8 dollars per user per month billed annually, and includes unlimited projects, AI-powered task management, and 500 AI credits per user each month, with a 14-day free trial. Enterprise pricing is custom and includes installation support, custom plugins, and white-labeling.$q$]::text[], 2);
