INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$AI Agents and Workflow Automation$q$, $q$AI-assisted workflows layered across every module to reduce manual HR admin work.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$1:1 Meetings and Instant Feedback$q$, $q$Structured meeting notes and lightweight feedback tools to support ongoing manager-employee conversations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Analytics and Q&A Boards$q$, $q$Cross-module reporting dashboards plus anonymous Q&A and whistleblowing channels.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Combines reviews, OKRs, surveys, learning, and compensation in one connected platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Modular pricing lets companies start with one module and expand later$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Strong European data-residency and GDPR posture out of the box$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$AI agents and automation are included across the shared platform layer, not gated to one module$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Broad language localization (38+ languages) suited to global teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$No published pricing; every quote requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$No permanent free plan, only a 14-day trial$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Minimum one-year contracts can reduce flexibility for smaller teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Dedicated Customer Success support is gated behind a minimum annual spend$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Full value requires adopting multiple modules, which raises total cost versus single-purpose tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$What is Leapsome used for?$q$, $q$Leapsome is used by HR and people teams to run performance reviews, track goals and OKRs, run engagement surveys, manage learning and development, and handle compensation planning in one connected platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$How much does Leapsome cost?$q$, $q$Leapsome uses modular, per-module pricing generally reported around $3 to $7 per employee per month per module, with typical blended costs of $8 to $15 per user per month; exact pricing requires a custom quote from sales.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Does Leapsome have a free plan?$q$, $q$No, Leapsome does not offer a permanent free plan, but it does offer a 14-day free trial without requiring a credit card.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Who founded Leapsome?$q$, $q$Leapsome was founded in 2016 by Jenny Podewils and Kajetan Armansperg, who serve as co-CEOs. The company is headquartered in Berlin, Germany.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Is Leapsome only for large enterprises?$q$, $q$No, Leapsome's modular pricing is designed to work for mid-market companies as well as larger enterprises, letting smaller organizations start with a single module like Reviews.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$What languages does Leapsome support?$q$, $q$Leapsome supports more than 38 languages, making it suited to companies with distributed, international workforces.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Unifying performance and engagement data$q$, $q$Mid-market companies replace separate review, survey, and OKR tools with Leapsome's connected modules to see performance and engagement data in one place.$q$, $q$HR and people operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Scaling performance reviews for growing teams$q$, $q$Fast-growing startups adopt the Reviews and Goals modules first to formalize performance management as headcount grows.$q$, $q$Startup and scale-up HR leaders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Global, multilingual HR programs$q$, $q$International companies use Leapsome's 38+ language support and GDPR-aligned infrastructure to run consistent people programs across regions.$q$, $q$Global and EU-headquartered enterprises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Reviews Module$q$, $q$Custom quote (reported from ~$3-7/user/month)$q$, $q$annual$q$, NULL, $q$["360-degree performance reviews","Continuous feedback","Competency frameworks"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Goals Module$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["OKR and goal tracking","Alignment dashboards"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Surveys Module$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Engagement and pulse surveys","Benchmarking"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Learning Module$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Course creation","Skills development tracking"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Compensation Module$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Compensation planning","Benchmarking","Pay-equity analysis"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$Multi-Module / Enterprise$q$, $q$Custom pricing$q$, $q$annual (min. 1 year)$q$, NULL, $q$["Multiple modules bundled","Volume discounts","Dedicated CS manager (min. spend applies)","SSO and ISO 27001 security"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Leapsome is a people enablement platform that brings together performance reviews, OKR/goal tracking, employee engagement surveys, learning and development, and compensation management into a single modular system for HR and people teams. It positions itself as an alternative to stitching together several disconnected point solutions for these functions.$q$, $q$Founded in 2016 in Berlin by co-CEOs Jenny Podewils and Kajetan Armansperg, Leapsome was bootstrapped and profitable for six years before raising a 60 million dollar Series A in 2022 led by Insight Partners. The company now serves more than 2,000 customers including Notion, Sony, and Porsche Digital, and has expanded with a New York office alongside its Berlin headquarters.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Leapsome's product is split into modules that customers select based on need: Reviews for 360-degree performance evaluations and continuous feedback, Goals for OKR tracking, Surveys for engagement and pulse feedback with benchmarking, Learning for course creation and skills development, and Compensation for pay planning and benchmarking, with newer HRIS and Time Tracking modules in progress.$q$, $q$Every customer also gets a shared layer of tools regardless of module selection, including AI agents and workflow automation, analytics dashboards, structured 1:1 meeting notes, instant feedback, a competency framework builder, an anonymous whistleblowing channel, and enterprise security certifications like ISO 27001, plus localization in more than 38 languages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdee0987-278e-4695-be35-6f8d4a24d46b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Leapsome uses modular, à la carte pricing rather than fixed tiers: companies choose which modules to buy (Reviews, Goals, Surveys, Learning, Compensation, and more), each priced per employee per month, generally reported in the range of about 3 to 7 dollars per module, with blended costs for common multi-module deployments often starting around 8 to 15 dollars per user per month.$q$, $q$Exact prices are not published; organizations must contact Leapsome's sales team for a custom quote based on employee count, module mix, and contract length, which typically runs a minimum of one year. There is no permanent free plan, but a 14-day free trial is available without a credit card, and dedicated Customer Success support is generally included for accounts above a minimum annual spend.$q$]::text[], 2);
