INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Stripe and PayPal Integration$q$, $q$Native payment processing for selling courses and memberships without a separate e-commerce plugin.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$AI Course Outline and Quiz Builder$q$, $q$Generates course structure and quiz questions from a topic prompt on Pro and Elite plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Groups and Cohorts$q$, $q$Manages cohort-based learning groups with shared progress tracking.$q$, 6);
