INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$No transaction or revenue-share fees on course sales, unlike many hosted platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Full ownership of course content and student data on your own WordPress site$q$, 1);
