INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$What is LearnDash used for?$q$, $q$LearnDash is a WordPress plugin used to build, sell, and manage online courses directly on a self-hosted WordPress website.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$How much does LearnDash cost?$q$, $q$LearnDash is sold as an annual license: Essentials at $259/year, Pro at $399/year, and Elite at $599/year, all with unlimited courses and learners.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Does LearnDash charge a fee on course sales?$q$, $q$No, LearnDash does not take a percentage cut of course sales, unlike some hosted platforms such as Teachable or Gumroad.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Who owns LearnDash?$q$, $q$LearnDash was created by Justin Ferriman in 2013 and acquired by Liquid Web's Family of Brands in 2021; it now operates as one of Liquid Web's core WordPress software products.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Does LearnDash require WordPress hosting?$q$, $q$Yes, the standard LearnDash plugin requires a self-hosted WordPress site, though a separate LearnDash Cloud product bundles managed hosting for those who prefer not to self-host.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Does LearnDash offer a free trial?$q$, $q$LearnDash offers a 48-hour trial without a credit card and a 15-day money-back guarantee, but no long-term free plan.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Selling standalone online courses$q$, $q$Independent creators and coaches use LearnDash to build and sell paid courses directly from their own branded WordPress site.$q$, $q$Course creators and coaches$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Corporate training and compliance$q$, $q$Businesses run internal training and compliance certification programs on WordPress using LearnDash's quizzes, certificates, and reporting.$q$, $q$Corporate training teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Cohort-based education programs$q$, $q$Educational organizations use groups, cohorts, and multi-instructor tools to run structured, instructor-led programs with multiple teachers.$q$, $q$Schools, universities, and training organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Essentials$q$, $q$$259/year$q$, $q$annual$q$, NULL, $q$["Drag-and-drop course builder","Quiz builder","Memberships and subscriptions","Stripe and PayPal integration","Video progression","Certificate builder and achievements","Plagiarism detection","Automated notifications","Unlimited courses and learners"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Pro$q$, $q$$399/year$q$, $q$annual$q$, NULL, $q$["Everything in Essentials","AI course outline and quiz builder","Advanced reporting and analytics","Enrollment tracking","Weighted grading","Report cards","Student notes","Groups and cohorts"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$Elite$q$, $q$$599/year$q$, $q$annual$q$, NULL, $q$["Everything in Pro","Group course management","Multi-instructor management","Front-end instructor role","Multi-instructor course collaboration","Ratings, reviews, and feedback collection"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LearnDash is a WordPress LMS plugin that lets businesses, schools, and independent creators build and sell online courses directly on a self-hosted WordPress site. Rather than hosting courses on a third-party platform, LearnDash installs into an existing WordPress install, giving site owners full control over design, data, and hosting.$q$, $q$The plugin launched in 2013, created by Justin Ferriman, and was acquired by Liquid Web's Family of Brands in September 2021, joining the StellarWP division of premium WordPress software. In 2026, Liquid Web consolidated its StellarWP portfolio, and LearnDash remained one of the four core surviving products, alongside Kadence, The Events Calendar, and Give.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$LearnDash's core toolset includes a drag-and-drop course builder, a quiz builder with multiple question types and randomized pools, assignment submission and grading, a certificate builder, membership and subscription gating, and native Stripe and PayPal checkout for selling courses without a separate e-commerce plugin.$q$, $q$Higher tiers add an AI-powered course outline and quiz generator, advanced reporting and enrollment analytics, weighted grading and report cards, groups and cohorts, and multi-instructor tools with a front-end instructor role, letting larger organizations run cohort-based or multi-teacher programs from a single WordPress install.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LearnDash is sold as an annual license in three tiers: Essentials at 259 dollars per year for core course-building and selling functionality, Pro at 399 dollars per year (the most popular tier) adding AI tools and advanced analytics, and Elite at 599 dollars per year adding multi-instructor and cohort management. All tiers include unlimited courses and unlimited learners with no per-student fees.$q$, $q$There is no free trial requiring a credit card, but LearnDash offers a 48-hour trial and a 15-day money-back guarantee. A separate LearnDash Cloud product bundles managed WordPress hosting with the LMS for buyers who do not want to self-host.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f765cfa6-721a-409a-a821-11862b637dcc', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
