INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$LinkedIn Automation$q$, $q$Automates connection requests, messages, and profile visits as part of multichannel sequences.$q$, 3);
