INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$lemAgent AI$q$, $q$AI assistant that helps draft and personalize outbound email and message copy.$q$, 5);
