INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$CRM Integrations$q$, $q$Native integrations with HubSpot, Salesforce, and Pipedrive alongside Gmail and LinkedIn.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Combines lead database, outreach, and deliverability tools in one subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Signature dynamic personalization (custom images/videos/landing pages) is a differentiated feature$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Multichannel plan covers email, LinkedIn, calling, SMS, and WhatsApp in one sequence$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Unlimited users on the Email plan with no per-seat fee$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$14-day free trial of the top Multichannel plan with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Email plan caps monthly sends at 50,000, requiring an upgrade for high-volume senders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Multichannel plan is priced per user, which scales quickly for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Data enrichment (emails, phone numbers, intent signals) runs on a separate pay-as-you-go credit system$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Enterprise pricing is not published and requires a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Deep multichannel feature set can have a learning curve for teams that only need basic cold email$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$What is Lemlist used for?$q$, $q$Lemlist is used by B2B sales teams to run personalized, multichannel outbound campaigns across email, LinkedIn, calling, SMS, and WhatsApp, backed by a built-in lead database and deliverability tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$How much does Lemlist cost?$q$, $q$Lemlist's Email plan starts at $55/month billed annually ($69 monthly), and the Multichannel plan starts at $87/user/month billed annually ($109 monthly); Enterprise pricing is custom for teams of 5 or more.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Does Lemlist offer a free trial?$q$, $q$Yes, Lemlist offers a 14-day free trial of its Multichannel plan with no credit card required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Who founded Lemlist?$q$, $q$Lemlist was founded in January 2018 in Paris, France by Guillaume Moubeche, Francois Lecroart, and Vianney Lecroart.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$What are Lemlist credits used for?$q$, $q$Credits are a separate pay-as-you-go currency used for data features like finding verified emails (5 credits), phone numbers (20 credits), and intent signals (20 to 400-plus credits), priced at $0.01 per credit.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Does Lemlist support LinkedIn outreach?$q$, $q$Yes, LinkedIn automation for connection requests, messages, and profile visits is included on the Multichannel plan and above.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Cold email lead generation$q$, $q$B2B sales teams run personalized cold email campaigns with automated warm-up to book more meetings while protecting sender reputation.$q$, $q$B2B SDRs and founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Multichannel outbound sequences$q$, $q$Sales teams combine email, LinkedIn, calling, and SMS into a single sequence to reach prospects across channels.$q$, $q$Mid-market sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Agency outbound campaigns for clients$q$, $q$Growth and lead-gen agencies use Lemlist's lead database and personalization tools to run outbound campaigns on behalf of client accounts.$q$, $q$B2B growth and lead-generation agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Email$q$, $q$$55/month (annual) / $69/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited users and senders","50,000 emails/month","650M+ lead database","Email finder","lemAgent AI","Unified inbox","Deliverability hub","CRM integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Multichannel$q$, $q$$87/user/month (annual) / $109/user/month (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["All Email features","Unlimited emails and messages","5 sending addresses/user","LinkedIn automation","In-app cold calling (Aircall)","SMS and WhatsApp outreach","Task management","~1,500 enrichment credits/user/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["5+ users","All Multichannel features","Custom roles and permissions","SSO/SAML","Dedicated account manager","1:1 onboarding","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lemlist is a sales engagement platform that began as a cold-email personalization tool and has grown into a full multichannel outbound platform, combining email, LinkedIn, calling, SMS, and WhatsApp outreach with a built-in B2B lead database and deliverability management.$q$, $q$Founded in January 2018 in Paris by Guillaume Moubeche, Francois Lecroart, and Vianney Lecroart, Lemlist was bootstrapped for its first several years before raising 30 million dollars from Expedition Growth Capital in October 2021 at a roughly 150 million dollar valuation. The company now operates from New York, serves over 37,000 businesses across 100-plus countries, and reported around 40 million dollars in annual recurring revenue in late 2024.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Lemlist's signature capability is dynamic personalization, letting senders auto-generate individualized images, videos, and landing pages for each recipient at scale, paired with a deliverability hub that manages email warm-up and sender reputation to keep campaigns out of spam folders. A built-in lead database of more than 650 million contacts includes a credit-based email and phone finder.$q$, $q$Beyond email, Lemlist supports LinkedIn automation for connection requests and messaging, an in-app cold-calling dialer integrated with Aircall, and SMS and WhatsApp outreach, all managed through a unified multichannel inbox with task management and native CRM integrations for HubSpot, Salesforce, and Pipedrive.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lemlist offers two self-serve plans: Email at 55 dollars per month billed annually (69 dollars monthly), priced per workspace with unlimited users but capped at 50,000 emails a month; and Multichannel at 87 dollars per user per month billed annually (109 dollars monthly), which removes the email cap and adds LinkedIn, calling, and messaging channels. Enterprise pricing is custom for teams of five or more.$q$, $q$Data features run on a separate pay-as-you-go credit system priced at 0.01 dollars per credit, where a verified email costs 5 credits and a phone number costs 20 credits. A 14-day free trial of the Multichannel plan is available with no credit card required, and annual billing saves 20 percent over monthly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
