INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('15ddf167-bf8b-4750-8dd7-0a160f126943', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Federated Instances (ActivityPub)$q$, $q$Independently hosted servers interconnect via ActivityPub so users on different instances can interact with the same communities.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Self-Hosting$q$, $q$Anyone can run their own Lemmy instance via Docker or Ansible, with low resource requirements thanks to its Rust backend.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Threaded Discussions and Voting$q$, $q$Reddit-style threaded comments with upvoting and downvoting on posts and replies.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Community Creation$q$, $q$Users can create and moderate their own topic-based communities within an instance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Transparent Moderation Logs$q$, $q$Publicly visible mod logs on each instance document moderation actions for accountability.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Data Erasure$q$, $q$Users can permanently delete their content and account data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Cross-Platform Apps$q$, $q$Official and community-built apps available for iOS, Android, desktop, and web.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Multilingual Support$q$, $q$Localized into more than 30 languages via a community translation project on Weblate.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Completely free and open source with no ads or tracking$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Federated architecture means no single company controls the network$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Lightweight Rust backend makes self-hosting cheap and accessible, even on a Raspberry Pi$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Transparent, publicly visible moderation logs on each instance$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Active community translation effort supporting 30+ languages$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Federated model means content and community quality vary significantly between instances$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Smaller overall user base than Reddit, so some communities are less active$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$No central support team; self-hosters are responsible for their own instance maintenance$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Discovering the right instance or community can be confusing for new users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Some apps and clients are community-built with varying levels of polish$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Is Lemmy free to use?$q$, $q$Yes, Lemmy is completely free and open source. Joining an existing instance costs nothing, and self-hosting your own instance only costs whatever server infrastructure you choose to run it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Who created Lemmy?$q$, $q$Lemmy was created in February 2019 by a developer known as Dessalines, along with co-creator Nutomic, as an open-source, decentralized alternative to Reddit.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$What is federation in Lemmy?$q$, $q$Federation means Lemmy instances (independently run servers) interconnect via the ActivityPub protocol, so users on one instance can view and interact with communities hosted on a different instance, similar to how email works across providers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Is Lemmy a company?$q$, $q$No, Lemmy is not a company. It is an open-source project with no headquarters or investors, licensed under the AGPL and funded through donations and grants.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$What programming language is Lemmy built with?$q$, $q$The Lemmy server is written in Rust, which gives it a small resource footprint capable of running on low-power hardware like a Raspberry Pi.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$How is Lemmy different from Reddit?$q$, $q$Unlike Reddit, Lemmy is decentralized across independently operated instances, is entirely open source and ad-free, and is funded by donations rather than advertising or venture capital.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Privacy-conscious community discussion$q$, $q$Users seeking an ad-free, non-corporate alternative to Reddit join or create Lemmy communities for topic-based discussion.$q$, $q$Privacy-conscious internet users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Self-hosted community forums$q$, $q$Organizations or hobbyist groups self-host their own Lemmy instance to run a fully independent, federated discussion forum for their community.$q$, $q$Self-hosting enthusiasts and community organizers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Fediverse participation$q$, $q$Open-source and decentralization advocates use Lemmy as part of the broader Fediverse alongside platforms like Mastodon.$q$, $q$Fediverse and open-source enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$Self-Hosted / Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source software (AGPL license)","Self-host your own federated instance","Threaded discussions and voting","Community creation and moderation tools","ActivityPub federation","No ads or tracking"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lemmy is a free, open-source link aggregator and discussion platform that works as a federated, self-hostable alternative to Reddit. Rather than living on one central website, Lemmy runs as independently operated 'instances' that interconnect through the ActivityPub protocol, the same open standard that powers Mastodon and the wider Fediverse.$q$, $q$The project was created in February 2019 by developer Dessalines, joined by co-creator Nutomic, as a deliberate reaction against centralized, ad-driven social platforms and their opaque moderation practices. Lemmy is not a company; it has no headquarters or investors, is licensed under the AGPL, and is funded through donations and grants, including support from the NLnet Foundation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Lemmy replicates classic forum and link-aggregation mechanics: threaded comments with upvoting and downvoting, community creation and subscription, user and community tagging, customizable themes, emoji and image support, NSFW flagging, and RSS/Atom feeds, all built on a lightweight Rust server that can run on hardware as modest as a Raspberry Pi.$q$, $q$Because it federates via ActivityPub, users on one Lemmy instance can subscribe to and interact with communities hosted on entirely different, independently run instances. Moderation is transparent through public mod logs on each instance, and there is no advertising or tracking, consistent with a donation-funded, non-commercial model.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lemmy has no pricing model or paid tiers; it is entirely free, open-source software distributed under the AGPL license. Users can join any existing public instance for free, or self-host their own instance using Docker or Ansible, in which case the only cost is the server infrastructure they choose to run it on.$q$, $q$There are no subscriptions, no premium features, and no company selling access to the software, since Lemmy is a community-maintained open-source project rather than a commercial product, funded through voluntary donations and grants such as those from the NLnet Foundation.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f318e3fc-7f57-48b4-8872-a1885a2bafc0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
