-- ── LeadIQ ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LeadIQ is a B2B sales prospecting platform that finds verified contact data, enriches CRM records, and tracks job changes for outbound sales teams.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid Pro plan from around $200/month)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$LeadIQ Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LeadIQ review covering B2B prospecting and lead-enrichment features, Free/Pro/Enterprise credit-based pricing, pros, cons, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LeadIQ is a B2B sales prospecting and lead-enrichment platform that helps sales development reps and account executives find verified email addresses and phone numbers, enrich CRM records, track job changes among past champions, and build outbound prospect lists faster than manual research. The company was founded in 2015 by Angelo Huang and Mei Siauw and is headquartered in San Francisco, California, with a second hub in Singapore and a globally distributed remote team. LeadIQ has raised a total of roughly 40 million dollars in venture funding across multiple rounds, most notably a 30 million dollar Series B in 2021; some data providers report slightly higher cumulative totals near 45.6 million dollars. As of the mid-2020s the company reported annual recurring revenue in the high single-digit millions and a headcount in the range of roughly 130 to 150 employees. Architecturally, LeadIQ operates as a browser extension (primarily for Chrome, working on LinkedIn and company websites), a web application, and a set of native integrations into CRMs (notably Salesforce and HubSpot) and sales engagement tools (such as Outreach and Salesloft), so reps can capture a prospect's contact details directly from LinkedIn or a company site and push them into their existing workflow without manual copy-paste. The platform's core functions include People Search for finding and verifying business emails and mobile numbers, Company Search for building account lists, CRM and webform enrichment that automatically fills in missing contact and firmographic data on existing records, Job Change / Champion Tracking that alerts reps when a past contact moves to a new company (a strong signal for re-engagement), an AI-powered outbound message writer that drafts personalized outreach copy, and a signals layer that surfaces buying-intent triggers. Enterprise customers additionally get AI account prospecting (Lando Agent), governance and admin controls, CSV/file-based bulk enrichment, Salesforce duplicate detection, team-level analytics dashboards, custom field mapping, and single sign-on. Pricing runs on a universal credits system that is spent across all product features; a single verified email typically costs one credit, a mobile phone number costs up to ten credits, and enriching a full email-plus-phone record costs eleven credits, with account-level enrichment costing a few credits per record. LeadIQ offers a genuinely usable Free plan (one user, fifty credits) that includes people search, API access, exporting, job-change tracking, the Chrome extension, the AI outbound writer, and core integrations; the Pro plan is priced at roughly 200 dollars per month for credit tiers that scale from around 200 up to several thousand credits monthly, with a 25 percent discount for annual billing, and a 30-day free trial is available on paid plans; Enterprise pricing is custom and, based on real purchase data reported by pricing-transparency vendors, typically runs from roughly 15,000 to 30,000 dollars per year for a mid-size sales organization, unlocking the AI prospecting agent, governance features, and dedicated support. Credits do not roll over month to month on most plans. LeadIQ's target audience is B2B sales development teams, account executives, and revenue operations functions at SaaS and technology companies who need a fast, workflow-embedded way to build accurate prospect lists and keep CRM data current, rather than a standalone data marketplace to browse independently. Its most direct competitors are ZoomInfo (a much larger, more expensive data platform with a broader intelligence suite), Apollo.io (a lower-cost, all-in-one prospecting-plus-sequencing tool), Cognism (strong in European/GDPR-compliant mobile data), Clearbit/Breeze Intelligence, Lusha, and Seamless.AI; LeadIQ differentiates itself by emphasizing prospecting speed directly inside the rep's existing workflow (LinkedIn, CRM, sales engagement tool) via its browser extension and by its job-change/champion-tracking feature for re-engaging past buyers who move companies, rather than trying to be the single system of record for all company and contact data the way ZoomInfo positions itself.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '88b216db-d52e-49cb-b940-093f9a2044aa';

