-- ── Leadpages ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Leadpages is a landing page and website builder that helps marketers and small businesses create, test, and optimize pages to capture leads and sales.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$49/month (promotional; regular $99/month)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Minneapolis, Minnesota, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Leadpages Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Leadpages review covering landing page builder features, Grow/Optimize/Scale pricing, AI page creation, pros, cons, and top marketing-tool alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Leadpages is a landing page and conversion-focused website builder aimed at marketers, small businesses, coaches, and course creators who need to publish pages that capture leads and drive sales without hiring a developer. The company was founded in 2012 in Minneapolis, Minnesota by Clay Collins and Tracy Simmons, releasing its first software in January 2013 with roughly two dozen templates and integrations for tools like AWeber, MailChimp, Infusionsoft, and GoToWebinar. Leadpages raised a Series A round of 5 million dollars in September 2013 from Foundry Group and Arthur Ventures and went on to raise a total of roughly 38 million dollars across three rounds. In March 2020 the company was acquired by Redbrick Technologies and now operates as part of the Redbrick portfolio, headquartered in the North Loop area of Minneapolis with team members across the Twin Cities, Victoria (Canada), and remotely across North America; Michael Sacca was appointed CEO in 2024. Architecturally, Leadpages is a hosted, no-code, drag-and-drop page builder: users pick from a library of conversion-optimized templates, customize them with a visual editor, and Leadpages hosts the resulting pages on its own infrastructure or a connected custom domain, with built-in tracking, analytics, and A/B testing baked into the hosting layer rather than requiring a separate testing tool. Core features include unlimited page publishing on paid plans, AI-assisted page creation and copywriting (consuming a monthly pool of AI credits), manual A/B split testing, Smart Traffic (an AI feature on higher tiers that automatically routes visitors to the highest-converting page variant for their device or source), click and scroll heatmaps, dynamic text replacement for personalizing headlines based on ad or search query, lead enrichment that appends firmographic data to form submissions, pop-ups and alert bars, and forms with native webhook support for connecting to email and marketing platforms. In 2026 Leadpages also introduced a companion product line called HTML Pub, a simpler, code-friendly page publishing product priced separately (Starter at 10 dollars per month for 5 pages, Pro at 29 dollars per month for 25 pages with API access and a blog, and Business at 49 dollars per month for 50 pages and two blogs), aimed at users who want more control over page markup and hosting than the standard Leadpages builder. The core Leadpages product itself is sold in three tiers: Grow at a regular price of 99 dollars per month (frequently discounted to 49 dollars for a first month), which includes unlimited traffic and pages, up to four custom domains with SSL, manual A/B testing, dynamic text replacement, lead enrichment for up to 2,000 IP lookups a month, and 40,000 monthly AI credits; Optimize at a regular price of 199 dollars per month (often discounted to 99 dollars for a first month), the most popular tier, which adds Smart Traffic AI routing, click and scroll heatmaps, auto-personalization, ten active integrations, 24-month analytics retention, and 80,000 AI credits; and Scale at 399 dollars per month, which adds a full auto-optimization loop, team seats and workspaces, a dedicated customer success manager, 25 integrations, 36-month analytics retention, and 160,000 AI credits. All plans include unlimited traffic, forms with webhooks, and a free trial (commonly cited as 7 to 14 days), and annual billing saves roughly 20 percent across plans. Leadpages targets small business owners, solo marketers, coaches, course creators, real estate agents, and marketing teams at small-to-mid-size companies who need to launch and test landing pages quickly without engineering resources. Its most direct competitors are Unbounce (similarly focused on conversion optimization and A/B testing for agencies and larger marketing teams), Instapage (enterprise-oriented personalization and testing), ClickFunnels (a broader funnel-and-sales-process builder rather than a pure page tool), and Landingi and HubSpot's landing page tools; Leadpages differentiates on price and simplicity for small businesses, its built-in Smart Traffic AI routing feature, and its heritage as one of the original standalone landing page products in the space.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd9e98516-f585-417e-b8e1-aa7ccf705fd5';

