-- ── Leantime ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Leantime is an open-source, goal-focused project management tool designed for non-project-managers, with features built for neurodivergent and ADHD users.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); Cloud Pro from $8/user/month billed annually$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Charlotte, North Carolina, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Leantime Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Leantime review covering open-source, ADHD-friendly project management features, free self-hosted and Cloud Pro pricing, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Leantime is an open-source project management platform explicitly designed for people who are not professional project managers, built around goal- and motivation-based workflows rather than the rigid task hierarchies found in traditional PM tools, and marketed specifically as friendly to neurodivergent users including people with ADHD, autism, and dyslexia. The open-source codebase began in 2019, and the company behind it was formally launched in 2022 by CEO Gloria Folaron, a former nurse turned product manager who built the first version of Leantime to manage her own ADHD-related overwhelm with existing project tools, and CTO Marcel Folaron, who immigrated from Germany and previously worked in technical program management roles at Google and Twilio. The company is headquartered in Charlotte, North Carolina, and joined the Techstars accelerator in 2023, giving it early institutional validation; the open-source project has grown to more than 50,000 downloads with an active Discord community. Architecturally, Leantime is available in two forms: a free, self-hosted, AGPLv3-licensed open-source edition (the Community Edition) that users deploy on their own infrastructure via Docker or a similar setup, and a paid, fully managed Cloud edition hosted by the company. Both editions share the same core feature set, built around ideas from behavioral and motivational science rather than pure task-tracking: task management with Kanban boards, task lists, and calendar views; milestone tracking with Gantt/timeline views; a built-in Lean Canvas and SWOT analysis tool for early-stage strategy and planning; a project wiki; timesheets and time tracking; retrospectives; goal and idea management; and notification integrations with Slack, Mattermost, and Discord, plus single sign-on via LDAP and OIDC. On the Cloud side, Leantime Pro adds AI-powered task management (an AI assistant that helps break down and prioritize work, backed by a monthly pool of AI credits), while paid Enterprise plans add single sign-on, audit logs, data residency controls, custom billing, and custom integrations, aimed at organizations with compliance or procurement requirements that self-hosting alone cannot satisfy. Pricing is straightforward relative to most SaaS project management tools: self-hosting the Community Edition is entirely free with no user limits, since it is genuinely open source software; the Cloud Pro plan costs 10 dollars per user per month billed monthly or 8 dollars per user per month billed annually (a roughly 17 percent discount, sometimes marketed as 'two months free'), and includes unlimited to-dos and projects, AI-powered task management, and 500 AI credits per user per month, with a 14-day free trial available before committing; Enterprise pricing is custom-quoted and includes installation assistance, custom plugins, and white-labeling support for larger deployments. Leantime's target audience splits into two groups: individual developers, freelancers, and small teams who want a fully free, self-hosted alternative to commercial project management SaaS and are comfortable running their own server, and small-to-mid-size teams (particularly startups, agencies, and neurodivergent-led or neurodivergent-friendly organizations) who want the same motivational, goal-first design philosophy but prefer a managed cloud product with AI features and without the operational overhead of self-hosting. Its most direct competitors in the open-source project management space include OpenProject, Taiga, Focalboard, Plane, and Redmine, while in the broader commercial project management category it is frequently compared to Trello, Asana, ClickUp, and Monday.com; Leantime differentiates itself from all of these primarily on its explicit neurodiversity- and ADHD-conscious design (goal- and motivation-oriented workflows instead of pure task lists, reduced cognitive load in the interface, and built-in strategy tools like Lean Canvas and SWOT) and on offering a genuinely free and unrestricted self-hosted open-source edition rather than a crippled free tier designed mainly to funnel users toward a paid plan.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cc8a6c27-5e21-4987-a514-54dffa799736';

