-- ── Leapsome ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Leapsome is a people enablement platform combining performance reviews, goals/OKRs, engagement surveys, learning, and compensation in one modular HR suite.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (modular, reported from around $8/user/month per module)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$101-250 employees$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$and 36+ additional languages$q$]::text[],
  seo_title = COALESCE($q$Leapsome Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Leapsome review covering people enablement features like reviews, OKRs, surveys, and learning, modular pricing, pros, cons, and HR platform alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Leapsome is a people enablement platform that unifies performance management, goal-setting (OKRs), employee engagement surveys, learning and development, compensation management, and core HR data into a single modular system for people teams. The company was founded in 2016 by Jenny Podewils and Kajetan Armansperg, who now serve as co-CEOs, and is headquartered in Berlin, Germany, with an additional office opened in New York City in 2022 to support its growing US customer base. Unusually for a venture-backed HR tech company, Leapsome operated as a bootstrapped and profitable business for its first six years before raising any outside capital; in 2022 it raised 60 million dollars in a Series A round led by Insight Partners with participation from Creandum and Visionaries Club, giving it runway to expand its modules and go-to-market team without having previously needed institutional funding to survive. As of the mid-2020s Leapsome reports serving more than 2,000 companies, including notable customers like Notion, Sony, and Porsche Digital, and employs roughly 150 people. Architecturally, Leapsome is built as a modular SaaS platform: rather than a single fixed product, it is composed of discrete modules that customers can mix and match, including Reviews (360-degree performance reviews and continuous feedback), Goals (OKR and goal-tracking), Surveys (employee engagement and pulse surveys with benchmarking), Learning (course creation and skills development), Compensation (compensation planning, benchmarking, and pay-equity analysis), and newer HRIS and Time Tracking modules that Leapsome has been building out to move further into core HR system-of-record territory (some in early access as of 2026). Every customer, regardless of which modules they buy, gets access to a shared underlying layer of AI Agents, workflow automation, analytics and reporting, Q&A boards, structured 1:1 meeting notes, instant feedback tools, a competency framework builder, a whistleblowing/anonymous reporting channel, a form builder, and enterprise security features including single sign-on, encryption, ISO 27001 certification, and GDPR compliance, along with localization support across more than 38 languages. Pricing follows an à la carte, module-based model rather than the fixed Basic/Pro/Enterprise tiers typical of most SaaS: organizations choose which modules they need (most commonly starting with Reviews, then adding Goals, Surveys, Learning, or Compensation as they grow), and per-employee, per-month pricing for each module is generally reported in the range of about 3 to 7 dollars, with typical blended starting costs for a multi-module deployment cited around 8 to 15 dollars per user per month depending on module mix, employee count, and negotiated multi-module or volume discounts; Leapsome does not publish exact prices on its website and requires organizations to contact sales for a quote, with contracts typically running a minimum of one year and Customer Success services (a dedicated CS manager and implementation support) generally reserved for accounts with a minimum annual spend, commonly cited around 6,000 dollars or more. There is no permanent free plan, but Leapsome offers a 14-day free trial without requiring a credit card. The platform's target audience is mid-market to enterprise HR and people operations teams, typically at companies from roughly 50 to a few thousand employees, that have outgrown spreadsheet-based performance reviews and disconnected point solutions and want a single system spanning the full employee performance and engagement lifecycle. Leapsome's most direct competitors include Lattice, 15Five, Culture Amp, Betterworks, and PerformYard in the performance-management and people-enablement space, along with broader HRIS players like Rippling and BambooHR as it expands into core HR; Leapsome differentiates itself through its modular, all-in-one breadth (combining reviews, OKRs, surveys, and learning under one roof rather than requiring separate point solutions), its European origin and strong GDPR/data-residency posture that appeals to EU-headquartered companies, and its emphasis on AI-assisted workflows layered across every module rather than confined to a single feature.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fdee0987-278e-4695-be35-6f8d4a24d46b';

