-- ── LearnDash ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$LearnDash is a WordPress LMS plugin that lets businesses, schools, and creators build, sell, and manage online courses directly on a WordPress site.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$259/year$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$LearnDash Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$LearnDash review covering WordPress LMS features, course builder, Essentials/Pro/Elite pricing, pros, cons, and top e-learning plugin alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$LearnDash is a learning management system (LMS) plugin for WordPress that lets businesses, educational institutions, membership sites, and individual creators build, sell, and manage online courses directly on a self-hosted WordPress website rather than a hosted third-party course platform. The plugin was first launched in 2013, created by Justin Ferriman, who had a background in the e-learning industry before building LearnDash. In September 2021, LearnDash was acquired by Liquid Web's Family of Brands and folded into StellarWP, Liquid Web's umbrella division for premium WordPress software (which also includes products like Kadence, GiveWP, and The Events Calendar); Liquid Web itself was founded in 1997 and is headquartered in Lansing, Michigan. In an April 2026 restructuring, Liquid Web announced that the StellarWP brand was being dissolved and its roughly ten sub-brands consolidated into four core products, with LearnDash remaining as one of the four surviving flagship products alongside Kadence, The Events Calendar, and Give. LearnDash is trusted by Fortune 500 companies, universities, and the agencies and consultants who build WordPress sites for them, and is one of the most widely adopted LMS plugins in the WordPress ecosystem. Architecturally, LearnDash is a self-hosted WordPress plugin, meaning it installs directly into an existing (or new) WordPress site and stores all course content, student data, and progress records in the site's own database rather than a third-party cloud platform; this gives site owners full data ownership and design control (courses inherit the site's WordPress theme) at the cost of requiring the buyer to handle their own WordPress hosting, unless they opt into LearnDash's newer hosted Cloud offering. Core functionality includes a drag-and-drop course builder for structuring lessons, topics, and modules; a quiz builder supporting multiple question types, timed quizzes, and randomized question pools; assignment submission and grading; a certificate builder that issues completion certificates and badges; membership and subscription models for gating content and recurring revenue; native Stripe and PayPal integration for selling courses and memberships; drip-feed content scheduling and video progression tracking that can require students to watch a set percentage of a video before advancing; plagiarism detection for written assignments; and automated email notifications for enrollment, completion, and other course events. Higher tiers add an AI-powered course outline and quiz builder that can auto-generate course structure and quiz questions from a topic prompt, advanced reporting and analytics, enrollment tracking, weighted grading, report cards, student notes, and support for groups and cohorts, while the top tier adds group course management, multi-instructor management with a front-end instructor role, multi-instructor course collaboration, and student ratings, reviews, and feedback collection. Pricing is structured in three annual license tiers that all include unlimited courses and unlimited learners with no per-student fees, unlike hosted alternatives that charge transaction fees: Essentials at 259 dollars per year covers the core course and quiz builder, memberships, Stripe/PayPal integration, video progression, certificates, plagiarism detection, and automated notifications; Pro at 399 dollars per year (the most popular tier) adds the AI course outline and quiz builder, advanced reporting and analytics, enrollment tracking, weighted grading, report cards, student notes, and groups and cohorts; and Elite at 599 dollars per year adds group course management, multi-instructor tools, and ratings and reviews. A separate LearnDash Cloud product offers a fully hosted version of the platform (including WordPress hosting) for buyers who do not want to manage their own server. There is no free trial with a credit card requirement, but LearnDash offers a 48-hour trial without one and a 15-day money-back guarantee. LearnDash's target audience spans course creators and coaches selling standalone paid courses, corporate training and compliance teams running internal LMS programs on WordPress, universities and training organizations, and WordPress agencies building e-learning sites for clients. Its most direct competitors include hosted, all-in-one course platforms like Teachable, Thinkific, and Kajabi (which charge platform or transaction fees but require no separate hosting), other WordPress LMS plugins such as Tutor LMS and LifterLMS, and enterprise LMS platforms like TalentLMS and Docebo for corporate training; LearnDash differentiates itself by taking no percentage cut of course sales (unlike Teachable's 7.5 percent fee on its Starter plan or Gumroad's 10 percent), by giving site owners full ownership of their WordPress site and student data, and by deep native integration with the broader WordPress plugin and theme ecosystem.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f765cfa6-721a-409a-a821-11862b637dcc';

