-- ── Lemmy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lemmy is a free, open-source, federated link aggregator and discussion platform built on ActivityPub, offering a self-hostable alternative to Reddit.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$and 30+ additional languages via community translation$q$]::text[],
  seo_title = COALESCE($q$Lemmy Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lemmy review covering this free, open-source federated Reddit alternative, self-hosting on ActivityPub, key features, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lemmy is a free and open-source, self-hostable link aggregator and discussion platform that functions as a federated alternative to Reddit, letting anyone run their own independent server ('instance') that interconnects with other Lemmy instances (and other compatible platforms) through the ActivityPub protocol, the same open federation standard used by Mastodon and the broader Fediverse. The project was created in February 2019 by a developer using the pseudonym Dessalines, with fellow developer Nutomic joining as a core co-creator; the two built Lemmy explicitly as a decentralized, non-commercial reaction against large centralized social platforms, motivated by concerns over surveillance capitalism, opaque and inconsistent moderation policies, and the erosion of user privacy and community autonomy on corporate-owned sites like Reddit. Dessalines has written that the project was nameless for a long time before settling on 'Lemmy,' chosen partly in homage to Motorhead's Lemmy Kilmister, who had died the week the name was chosen, and partly to continue the Fediverse tradition of naming projects after animals (referencing the video game Lemmings). Lemmy is not a company and has no headquarters, founders' equity, or investors; it is licensed under the GNU Affero General Public License (AGPL) and funded through donations and grants, including support from the NLnet Foundation, which funds public-benefit internet and open-source infrastructure projects. Architecturally, the Lemmy server is written in Rust, giving it a notably small resource footprint that the project explicitly advertises as being able to run on hardware as modest as a Raspberry Pi, and it is distributed via Docker and Ansible deployment scripts, so any individual or community can self-host a fully independent instance rather than depending on a single central server. Once running, a Lemmy instance federates with other instances (and, more broadly, other ActivityPub-compatible platforms) so that users on one server can subscribe to and interact with communities hosted on a different server, similar in concept to how email works across providers; this federated model means there is no single 'Lemmy' website, but rather a network of independently operated instances (such as lemmy.world and lemmy.ml, among many others) each with their own moderation policies, community focus, and hosting operator. Core features mirror and extend classic Reddit-style forum mechanics: threaded comments with upvoting and downvoting, community ('sub' equivalent) creation and subscription, user tagging with @ and community tagging with !, customizable light, dark, and solarized themes, emoji support and image uploading, NSFW community flagging, RSS/Atom feed support, email notifications, and full data-erasure tools that let users permanently delete their content. Moderation on Lemmy is designed to be transparent, with publicly visible mod logs on each instance, and there is no advertising or user tracking built into the platform, consistent with its funding model of donations rather than ad revenue or venture capital. There are official and community-built native apps for iOS, Android, desktop, and web, and the platform has been localized into more than 30 languages through a community-driven translation project hosted on Weblate. Because Lemmy is entirely free, open-source, and self-hostable, there is no pricing model, no paid tier, and no company selling subscriptions; any cost a user incurs comes only from self-hosting infrastructure (a VPS, a home server, or similar) if they choose to run their own instance rather than joining an existing public one. Lemmy's target audience includes privacy-conscious users seeking an alternative to centralized platforms following controversial Reddit policy changes (such as the 2023 API pricing changes that prompted many users and moderators to look for alternatives), open-source and Fediverse enthusiasts, and self-hosting communities who want full control over their own discussion forums. Its most direct competitors and comparable projects are other Fediverse link-aggregator and forum software, primarily Kbin/Mbin (a similar ActivityPub-based link aggregator with a somewhat different community model) and, more loosely, Mastodon (microblogging rather than link aggregation) within the same ActivityPub ecosystem; outside the Fediverse, Lemmy is most often compared directly to Reddit itself, which it was explicitly built to offer a decentralized, ad-free, non-corporate alternative to.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f318e3fc-7f57-48b4-8872-a1885a2bafc0';

